def difference(d1, d2, level=-1):
    """
    Return a dictionary with items from *d1* not contained in *d2*.

    *level* sets the maximum depth of recursion. For infinite recursion,
    set that to -1. For level 1,
    if a key is present both in *d1* and *d2* but has different values,
    it is included into the difference.
    See :func:`intersection` for more details.

    *d1* and *d2* remain unchanged. However, *d1* or some of its
    subdictionaries may be returned directly.
    Make a deep copy of the result when appropriate.

    .. versionadded:: 0.5
       add keyword argument *level*.
    """
    if level == 0:
        return {}

    diff = {}
    for key, value in d1.items():
        if key not in d2:
            diff[key] = value
        elif isinstance(value, dict) and isinstance(d2[key], dict) and level != 1:
            sub_diff = difference(value, d2[key], level - 1 if level != -1 else -1)
            if sub_diff:
                diff[key] = sub_diff
        elif d1[key] != d2[key]:
            diff[key] = value

    return diff

def fill(self, coord, weight=1):
    """
    Fill histogram at *coord* with the given *weight*.

    Coordinates outside the histogram edges are ignored.
    """
    if self.is_within_bounds(coord):
        self.histogram[coord] += weight

def is_within_bounds(self, coord):
    """
    Check if the given coordinate is within the histogram bounds.
    """
    return all(0 <= c < dim for c, dim in zip(coord, self.histogram.shape))

import re
from typing import Dict, List, Union

class ValidationError(Exception):
    def __init__(self, messages: List[Dict[str, str]]):
        self.messages = messages
        super().__init__(str(messages))

def _validate_labels(labels: Dict[Union[str, bool], Union[str, List, bool]]) -> None:
    """
    Check that keys and values in the given labels match against their corresponding
    regular expressions.

    Args:
        labels (dict): the different labels to validate.

    Raises:
        ValidationError: if any of the keys and labels does not match their respective
            regular expression. The error contains as message the list of all errors
            which occurred in the labels. Each element of the list is a dictionary with
            one key-value pair:
            - key: the label key or label value for which an error occurred as string.
            - value: the error message.
    """
    errors = []
    key_regex = re.compile(r'^[a-zA-Z_][a-zA-Z0-9_]*$')  # Example regex for keys
    value_regex = re.compile(r'^[a-zA-Z0-9_]+$')  # Example regex for values

    for key, value in labels.items():
        # Validate key
        if not isinstance(key, str):
            errors.append({str(key): 'expected string or bytes-like object'})
        elif not key_regex.match(key):
            errors.append({key: f"Label key '{key}' does not match the regex {key_regex.pattern}"})

        # Validate value
        if isinstance(value, list):
            for item in value:
                if not isinstance(item, str):
                    errors.append({str(item): 'expected string or bytes-like object'})
                elif not value_regex.match(item):
                    errors.append({item: f"Label value '{item}' does not match the regex {value_regex.pattern}"})
        else:
            if not isinstance(value, str):
                errors.append({str(value): 'expected string or bytes-like object'})
            elif not value_regex.match(value):
                errors.append({value: f"Label value '{value}' does not match the regex {value_regex.pattern}"})

    if errors:
        raise ValidationError(errors)

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Together with :func:``update_last_applied_manifest_dict_from_resp``, this
    function is called recursively to update a partial ``last_applied_manifest``
    from a partial Kubernetes response

    Args:
        last_applied_manifest (list): partial ``last_applied_manifest`` being
            updated
        observer_schema (list): partial ``observer_schema``
        response (list): partial response from the Kubernetes API.

    This function go through all observed fields, and initialized their value in
    last_applied_manifest if they are not yet present
    """
    for i, (schema_item, resp_item) in enumerate(zip(observer_schema, response)):
        if isinstance(schema_item, dict) and isinstance(resp_item, dict):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append({})
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        elif isinstance(schema_item, list) and isinstance(resp_item, list):
            if i >= len(last_applied_manifest):
                last_applied_manifest.append([])
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[i], schema_item, resp_item
            )
        else:
            if i >= len(last_applied_manifest):
                last_applied_manifest.append(resp_item)
            else:
                last_applied_manifest[i] = resp_item

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Together with :func:``update_last_applied_manifest_list_from_resp``, this
    function is called recursively to update a partial ``last_applied_manifest``
    from a partial Kubernetes response

    Args:
        last_applied_manifest (dict): partial ``last_applied_manifest`` being
            updated
        observer_schema (dict): partial ``observer_schema``
        response (dict): partial response from the Kubernetes API.

    Raises:
        KeyError: If the observed field is not present in the Kubernetes response

    This function go through all observed fields, and initialized their value in
    last_applied_manifest if they are not yet present
    """
    for key, schema in observer_schema.items():
        if key not in response:
            raise KeyError(f"Observed field '{key}' not present in the Kubernetes response")

        if key not in last_applied_manifest:
            if isinstance(schema, dict):
                last_applied_manifest[key] = {}
                update_last_applied_manifest_dict_from_resp(last_applied_manifest[key], schema, response[key])
            elif isinstance(schema, list):
                last_applied_manifest[key] = []
                update_last_applied_manifest_list_from_resp(last_applied_manifest[key], schema, response[key])
            else:
                last_applied_manifest[key] = response[key]

def generate_default_observer_schema(app):
    """
    Generate the default observer schema for each Kubernetes resource present in
    ``spec.manifest`` for which a custom observer schema hasn't been specified.

    Args:
        app (krake.data.kubernetes.Application): The application for which to generate a
            default observer schema
    """
    if not app.spec.manifest:
        return

    default_schema = {
        "type": "object",
        "properties": {
            "status": {
                "type": "object",
                "properties": {
                    "conditions": {
                        "type": "array",
                        "items": {
                            "type": "object",
                            "properties": {
                                "type": {"type": "string"},
                                "status": {"type": "string"},
                                "lastTransitionTime": {"type": "string"},
                                "reason": {"type": "string"},
                                "message": {"type": "string"}
                            },
                            "required": ["type", "status"]
                        }
                    }
                }
            }
        },
        "required": ["status"]
    }

    for resource in app.spec.manifest:
        if not hasattr(resource, 'observer_schema') or not resource.observer_schema:
            resource.observer_schema = default_schema

