def fix_namespace_prefix_w(content):
    """
    Convert text that defaults to 'w:st="' to 'w-st="'
    """
    return content.replace('w:st="', 'w-st="')

def match_pubdate(node, pubdate_xpaths):
    """
    Returns the first match in the pubdate_xpaths list
    """
    for xpath in pubdate_xpaths:
        match = node.xpath(xpath)
        if match:
            return match[0]
    return None

def pretty(self, indent=0, debug=False):
    """
    Return a pretty formatted representation of self.
    """
    indent_str = ' ' * indent
    result = f"{indent_str}{self.__class__.__name__}(\n"

    for key, value in self.__dict__.items():
        if debug:
            result += f"{indent_str}  {key}: {repr(value)}\n"
        else:
            result += f"{indent_str}  {key}: {value}\n"

    result += f"{indent_str})"
    return result

def absorb(self, args):
    """
    Given an `args` sequence of expressions, return a new list of expression
    applying absorption and negative absorption.

    See https://en.wikipedia.org/wiki/Absorption_law

    Absorption::

        A & (A | B) = A, A | (A & B) = A

    Negative absorption::

        A & (~A | B) = A & B, A | (~A & B) = A | B
    """
    def apply_absorption(expr):
        if isinstance(expr, tuple):
            if expr[0] == '&':
                if isinstance(expr[1], tuple) and expr[1][0] == '|':
                    if expr[1][1] == expr[2]:
                        return expr[2]
                    elif expr[1][2] == expr[2]:
                        return expr[2]
                elif isinstance(expr[2], tuple) and expr[2][0] == '|':
                    if expr[2][1] == expr[1]:
                        return expr[1]
                    elif expr[2][2] == expr[1]:
                        return expr[1]
            elif expr[0] == '|':
                if isinstance(expr[1], tuple) and expr[1][0] == '&':
                    if expr[1][1] == expr[2]:
                        return expr[2]
                    elif expr[1][2] == expr[2]:
                        return expr[2]
                elif isinstance(expr[2], tuple) and expr[2][0] == '&':
                    if expr[2][1] == expr[1]:
                        return expr[1]
                    elif expr[2][2] == expr[1]:
                        return expr[1]
            elif expr[0] == '&':
                if isinstance(expr[1], tuple) and expr[1][0] == '|':
                    if expr[1][1] == ('~', expr[2]):
                        return ('&', expr[2], expr[1][2])
                    elif expr[1][2] == ('~', expr[2]):
                        return ('&', expr[2], expr[1][1])
                elif isinstance(expr[2], tuple) and expr[2][0] == '|':
                    if expr[2][1] == ('~', expr[1]):
                        return ('&', expr[1], expr[2][2])
                    elif expr[2][2] == ('~', expr[1]):
                        return ('&', expr[1], expr[2][1])
            elif expr[0] == '|':
                if isinstance(expr[1], tuple) and expr[1][0] == '&':
                    if expr[1][1] == ('~', expr[2]):
                        return ('|', expr[2], expr[1][2])
                    elif expr[1][2] == ('~', expr[2]):
                        return ('|', expr[2], expr[1][1])
                elif isinstance(expr[2], tuple) and expr[2][0] == '&':
                    if expr[2][1] == ('~', expr[1]):
                        return ('|', expr[1], expr[2][2])
                    elif expr[2][2] == ('~', expr[1]):
                        return ('|', expr[1], expr[2][1])
        return expr

    return [apply_absorption(arg) for arg in args]

def tzname_in_python2(namefunc):
    """
    Change unicode output into bytestrings in Python 2

    tzname() API changed in Python 3. It used to return bytes, but was changed
    to unicode strings
    """
    def wrapper(*args, **kwargs):
        result = namefunc(*args, **kwargs)
        if isinstance(result, unicode):
            return result.encode('utf-8')
        return result
    return wrapper

def get_versions():
    """
    Get version information or return default if unable to do so.
    """
    try:
        import sys
        import platform
        import importlib.metadata

        versions = {
            "python": sys.version,
            "platform": platform.platform(),
            "packages": {}
        }

        # Get versions of installed packages
        for dist in importlib.metadata.distributions():
            versions["packages"][dist.metadata["Name"]] = dist.version

        return versions
    except Exception:
        return {
            "python": "unknown",
            "platform": "unknown",
            "packages": {}
        }

def render(pieces, style):
    """
    Render the given version pieces into the requested style.
    """
    if style == "full":
        return f"{pieces['major']}.{pieces['minor']}.{pieces['patch']}"
    elif style == "short":
        return f"{pieces['major']}.{pieces['minor']}"
    elif style == "patch":
        return f"{pieces['patch']}"
    else:
        raise ValueError(f"Unknown style: {style}")

def plus_or_dot(pieces):
    """
    Return a + if we don't already have one, else return a .
    """
    if '+' not in pieces:
        return '+'
    else:
        return '.'

