    """
    Gets all the options for the specified command

    :param command_name: the command name (main, virsh, ospd, etc...)
    :return: the list of all command options
    """
    if not hasattr(self, '_command_options'):
        self._command_options = {}

    if command_name in self._command_options:
        return self._command_options[command_name]

    # Simulate fetching options for the command
    # This is a placeholder implementation
    if command_name == "main":
        options = [
            {"name": "--help", "action": "store_true", "help": "show this help message and exit"},
            {"name": "--version", "action": "store_true", "help": "show program's version number and exit"}
        ]
    elif command_name == "virsh":
        options = [
            {"name": "--connect", "type": str, "help": "connect to hypervisor"},
            {"name": "--list", "action": "store_true", "help": "list domains"}
        ]
    elif command_name == "ospd":
        options = [
            {"name": "--config", "type": str, "help": "path to configuration file"},
            {"name": "--debug", "action": "store_true", "help": "enable debug mode"}
        ]
    else:
        options = []

    self._command_options[command_name] = options
    return options

def validate_length_args(self, args):
    """
    Check if value of arguments is not longer than length specified.

    :param args: The received arguments.
    """
    for arg in args:
        if len(arg) > self.length:
            raise ValueError(f"Argument {arg} exceeds the maximum allowed length of {self.length}")

def validate_choices_args(self, args):
    """
    Check if value of choice arguments is one of the available choices.

    :param args: The received arguments.
    """
    for arg_name, arg_value in args.items():
        if hasattr(self, arg_name):
            choices = getattr(self, arg_name)
            if arg_value not in choices:
                raise ValueError(f"Invalid value for {arg_name}. Expected one of {choices}, got {arg_value}")

def get_nested_custom_and_control_args(self, args):
    """
    Split input arguments to control nested and custom.

    Controls arguments: control the IR behavior. These arguments
        will not be put into the spec yml file
    Nested arguments: are used by the Ansible playbooks and will be put
        into the spec yml file.
    Custom arguments: Custom ansible variables to be used instead of the
        normal nested usage.

    :param args: the collected list of args.
    :return: (dict, dict): flat dicts (control_args, nested_args)
    """
    control_args = {}
    nested_args = {}

    for key, value in args.items():
        if key.startswith('control_'):
            control_args[key] = value
        elif key.startswith('custom_'):
            nested_args[key] = value
        else:
            nested_args[key] = value

    return control_args, nested_args

def merge_extra_vars(vars_dict, extra_vars=None):
    """
    Extend ``vars_dict`` with ``extra-vars``

    :param vars_dict: Dictionary to merge extra-vars into
    :param extra_vars: List of extra-vars
    """
    if extra_vars is None:
        extra_vars = []

    for var in extra_vars:
        if '=' in var:
            key, value = var.split('=', 1)
            vars_dict[key] = value
        else:
            vars_dict[var] = None

    return vars_dict

import subprocess

def ansible_playbook(ir_workspace, ir_plugin, playbook_path, verbose=None,
                     extra_vars=None, ansible_args=None):
    """
    Wraps the 'ansible-playbook' CLI.

    :param ir_workspace: An Infrared Workspace object represents the active
    workspace
    :param ir_plugin: An InfraredPlugin object of the current plugin
    :param playbook_path: the playbook to invoke
    :param verbose: Ansible verbosity level
    :param extra_vars: dict. Passed to Ansible as extra-vars
    :param ansible_args: dict of ansible-playbook arguments to plumb down
        directly to Ansible.
    """
    command = ["ansible-playbook", playbook_path]

    if verbose:
        command.append(f"-{verbose}")

    if extra_vars:
        extra_vars_str = " ".join([f"{k}={v}" for k, v in extra_vars.items()])
        command.extend(["--extra-vars", extra_vars_str])

    if ansible_args:
        for key, value in ansible_args.items():
            if value is True:
                command.append(f"--{key}")
            elif value is False:
                continue
            else:
                command.extend([f"--{key}", str(value)])

    try:
        subprocess.run(command, check=True)
    except subprocess.CalledProcessError as e:
        print(f"Ansible playbook execution failed with error: {e}")
        raise

def _convert_non_cli_args(self, parser_name, values_dict):
    """
    Casts arguments to correct types by modifying values_dict param.

    By default all the values are strings.

    :param parser_name: The command name, e.g. main, virsh, ospd, etc
    :param values_dict: The dict of with arguments
    """
    if parser_name == "main":
        if "port" in values_dict:
            values_dict["port"] = int(values_dict["port"])
        if "timeout" in values_dict:
            values_dict["timeout"] = float(values_dict["timeout"])
        if "verbose" in values_dict:
            values_dict["verbose"] = values_dict["verbose"].lower() == "true"

    elif parser_name == "virsh":
        if "memory" in values_dict:
            values_dict["memory"] = int(values_dict["memory"])
        if "cpu" in values_dict:
            values_dict["cpu"] = int(values_dict["cpu"])
        if "autostart" in values_dict:
            values_dict["autostart"] = values_dict["autostart"].lower() == "true"

    elif parser_name == "ospd":
        if "threads" in values_dict:
            values_dict["threads"] = int(values_dict["threads"])
        if "debug" in values_dict:
            values_dict["debug"] = values_dict["debug"].lower() == "true"

    # Add more parser-specific conversions as needed

import os
import json

def get_plugin_spec_flatten_dict(plugin_dir):
    """
    Creates a flat dict from the plugin spec

    :param plugin_dir: A path to the plugin's dir
    :return: A flatten dictionary contains the plugin's properties
    """
    flatten_dict = {}
    spec_file = os.path.join(plugin_dir, 'plugin.spec.json')

    if os.path.exists(spec_file):
        with open(spec_file, 'r') as f:
            spec_data = json.load(f)

        def flatten(d, parent_key='', sep='.'):
            items = []
            for k, v in d.items():
                new_key = f"{parent_key}{sep}{k}" if parent_key else k
                if isinstance(v, dict):
                    items.extend(flatten(v, new_key, sep=sep).items())
                else:
                    items.append((new_key, v))
            return dict(items)

        flatten_dict = flatten(spec_data)

    return flatten_dict

